//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String package;
    String license;
    String main;
    String types;
    String repository;
    Scripts scripts;
    Dependencies dependencies;
    DevDependencies devDependencies;
    List<String> files;

    Package({
        required this.name,
        required this.version,
        required this.package,
        required this.license,
        required this.main,
        required this.types,
        required this.repository,
        required this.scripts,
        required this.dependencies,
        required this.devDependencies,
        required this.files,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        package: json["package"],
        license: json["license"],
        main: json["main"],
        types: json["types"],
        repository: json["repository"],
        scripts: Scripts.fromJson(json["scripts"]),
        dependencies: Dependencies.fromJson(json["dependencies"]),
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
        files: List<String>.from(json["files"].map((x) => x)),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "package": package,
        "license": license,
        "main": main,
        "types": types,
        "repository": repository,
        "scripts": scripts.toJson(),
        "dependencies": dependencies.toJson(),
        "devDependencies": devDependencies.toJson(),
        "files": List<dynamic>.from(files.map((x) => x)),
    };
}

class Dependencies {
    String quicktypeCore;
    String collectionUtils;
    String graphql;

    Dependencies({
        required this.quicktypeCore,
        required this.collectionUtils,
        required this.graphql,
    });

    factory Dependencies.fromJson(Map<String, dynamic> json) => Dependencies(
        quicktypeCore: json["quicktype-core"],
        collectionUtils: json["collection-utils"],
        graphql: json["graphql"],
    );

    Map<String, dynamic> toJson() => {
        "quicktype-core": quicktypeCore,
        "collection-utils": collectionUtils,
        "graphql": graphql,
    };
}

class DevDependencies {
    String typesNode;
    String typesGraphql;
    String typescript;

    DevDependencies({
        required this.typesNode,
        required this.typesGraphql,
        required this.typescript,
    });

    factory DevDependencies.fromJson(Map<String, dynamic> json) => DevDependencies(
        typesNode: json["@types/node"],
        typesGraphql: json["@types/graphql"],
        typescript: json["typescript"],
    );

    Map<String, dynamic> toJson() => {
        "@types/node": typesNode,
        "@types/graphql": typesGraphql,
        "typescript": typescript,
    };
}

class Scripts {
    String clean;
    String build;

    Scripts({
        required this.clean,
        required this.build,
    });

    factory Scripts.fromJson(Map<String, dynamic> json) => Scripts(
        clean: json["clean"],
        build: json["build"],
    );

    Map<String, dynamic> toJson() => {
        "clean": clean,
        "build": build,
    };
}
